{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/WrappingRuleIssueTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for the fix of the issue: `wrapping`: raw string false positive `Missing newline after "{"`
 * 
 * When a raw string contains a lambda expression (e.g., inside a `let` block), 
 * and the raw string itself is long enough to trigger max_line_length checks,
 * the wrapping rule should not incorrectly flag the lambda's opening brace.
 */
internal class WrappingRuleIssueTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Issue - No false positive for lambda inside raw string with long line length`() {
        val code =
            """
            package test

            class QueryGenerator {
                fun getQueryString(query: QueryRequest): String {
                    val q = $MULTILINE_STRING_QUOTE
                        SELECT *
                        FROM table_name_long_enough_so_max_line_length_is_met_and_wrapping_rule_is_violated_and_generates_an_error
                        WHERE 1 = 1
                        $.{query.gameId?.let { "AND id = ?" } ?: ""}    
                    $MULTILINE_STRING_QUOTE
                    return q
                }
            }

            data class QueryRequest(
                val gameId: String?,
            )
            """.trimIndent()
                .replace("$.", "$")
        wrappingRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue - No false positive for lambda inside regular string template with long line`() {
        val code =
            """
            fun foo(value: String?) {
                val result = "This is a very long string that goes on and on and on and on and on and on and $.{value?.let { "suffix" } ?: ""}"
            }
            """.trimIndent()
                .replace("$.", "$")
        wrappingRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue - Lambda in multiline raw string should not trigger wrapping`() {
        val code =
            """
            fun generateQuery(id: String?): String {
                return $MULTILINE_STRING_QUOTE
                    SELECT * 
                    FROM users
                    WHERE 1=1
                    $.{id?.let { "AND id = ${'$'}it" } ?: ""}
                $MULTILINE_STRING_QUOTE.trimIndent()
            }
            """.trimIndent()
                .replace("$.", "$")
        wrappingRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Lambda outside string template should still follow wrapping rules`() {
        val code =
            """
            fun foo() {
                val result = someFunction({ x ->
                    println(x)
                })
            }
            """.trimIndent()
        wrappingRuleAssertThat(code)
            .hasNoLintViolations()
    }

    companion object {
        private const val MULTILINE_STRING_QUOTE = "\"\"\""
    }
}
"}

